export function generateInternalEdges(levelMap,mask,cfg){if(!cfg.internal)return null;const seg=[];const w=levelMap.width,h=levelMap.height,m=levelMap.map;for(let y=0;y<h-1;y++)for(let x=0;x<w-1;x++){const i=y*w+x;if(!mask[i])continue;const r=i+1,d=i+w;if(mask[r]&&Math.abs(m[i]-m[r])>=cfg.minToneJump)seg.push({x1:x+1,y1:y,x2:x+1,y2:y+1});if(mask[d]&&Math.abs(m[i]-m[d])>=cfg.minToneJump)seg.push({x1:x,y1:y+1,x2:x+1,y2:y+1})}return {id:'internal_edges',name:'Internal tone edges',type:'edge',color:cfg.color,strokeWidth:cfg.strokeWidth,visible:true,segments:seg,stats:{segments:seg.length}}}
